// ensureModuleInit checks that we're in a Go module and go.sum exists.
func ensureModuleInit() error {
	if _, err := os.Stat("go.mod"); os.IsNotExist(err) {
		fmt.Println("  No go.mod found. Please run 'go mod init <module>' first.")
		return fmt.Errorf("go.mod not found in current directory")
	}
	return nil
}

// installDependency installs a single dependency with version pinning.
// It does NOT use -insecure flag as that disables TLS verification,
// making the download vulnerable to man-in-the-middle attacks.
// For internal repos without proper certs, the correct solution is to
// configure the system/Go to trust the internal CA, not to disable TLS.
func installDependency(dep DependencyConfig) error {
	packageSpec := dep.Package
	if dep.Version != "" {
		packageSpec = dep.Package + "@" + dep.Version
	} else {
		// If no version specified, require @latest explicitly rather than
		// allowing arbitrary resolution.
		packageSpec = dep.Package + "@latest"
		fmt.Printf("  WARNING: No version pinned for %s, using @latest. "+
			"Pin a specific version for reproducible builds.\n", dep.Package)
	}

	if dep.IsInternal {
		fmt.Printf("  Installing (private): %s\n", packageSpec)
		// For internal packages, GOPRIVATE is already configured to bypass
		// the public proxy and sumdb. If the internal repo has self-signed certs,
		// configure GOINSECURE for that specific host pattern (not globally).
		// Better yet, add the internal CA to the system trust store.
		//
		// Example of scoped insecure config (only if absolutely necessary):
		//   os.Setenv("GOINSECURE", "git.internal.company.com")
		// This is still preferable to go get -insecure which was removed in Go 1.16+
	} else {
		fmt.Printf("  Installing: %s\n", packageSpec)
	}

	// Use 'go get' with the pinned version
	args := []string{"get", packageSpec}
	return runGoCommand(args...)
}

// verifyModules runs 'go mod verify' to check that dependencies in the local
// cache match the expected cryptographic hashes in go.sum.
func verifyModules() error {
	return runGoCommand("mod", "verify")
}

// runGoCommand executes a go command with the given arguments.
func runGoCommand(args ...string) error {
	cmd := exec.Command("go", args...)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr

	// Inherit the current environment (which includes our GOPRIVATE etc.)
	cmd.Env = os.Environ()

	cmdStr := "go " + strings.Join(args, " ")
	fmt.Printf("    Running: %s\n", cmdStr)

	if err := cmd.Run(); err != nil {
		return fmt.Errorf("command '%s' failed: %w", cmdStr, err)
	}
	return nil
}